        "content": "{\n  \"name\": \"shell\",\n  \"description\": \"Interactive command shell for nodes.\",\n  \"version\": \"0.1.0\",\n  \"runtime\": \"web-ui\",\n  \"entrypoints\": [\n    {\n      \"name\": \"shell\",\n      \"kind\": \"ui\",\n      \"route\": \"/apps/shell\",\n      \"icon\": { \"kind\": \"builtin\", \"id\": \"shell\" },\n      \"syscalls\": [\"shell.exec\", \"sys.device.list\"],\n      \"windowDefaults\": { \"width\": 980, \"height\": 640, \"minWidth\": 700, \"minHeight\": 420 },\n      \"module\": \"ui/worker.ts\",\n      \"description\": \"Interactive command shell for nodes.\"\n    }\n  ],\n  \"capabilities\": {\n    \"bindings\": [\n      {\n        \"binding\": \"KERNEL\",\n        \"kind\": \"kernel\",\n        \"interfaceName\": \"gsv.kernel.app.v1\",\n        \"required\": true,\n        \"description\": \"Package-scoped req/res binding for kernel-native syscalls.\"\n      }\n    ],\n    \"egress\": { \"mode\": \"none\" }\n  },\n  \"artifact\": {\n    \"mainModule\": \"ui/worker.ts\",\n    \"compatibilityDate\": \"2026-01-28\"\n  }\n}\n"
